 21→    /** 硬编码的 AI 分析 system_prompt */
 22→    private const SYSTEM_PROMPT = '# Role
 23→你是一位拥有 10 年以上经验的高级运营总监及项目管理专家，擅长从繁杂的员工日报中抽丝剥茧，精准捕捉各部门的关键进展、潜在风险以及团队协作中的断层。
 24→
 25→# Task
 26→我将为你提供一份各部门员工的日报汇总。请你作为我的"管理顾问"，通过内容特征识别成员的基础职能(仅使用基础称谓如：程序、美术、策划、运营、测试、行政等，不带高级/资深等头衔)，再按照以下框架进行深度解读，帮我识别出今天最值得关注的大事。
 27→
 28→# Analysis Framework
 29→请对日报进行解析，输出以下内容：
 30→
 31→- 核心里程碑 (Functions & Milestones)：
 32→  - 谁完成了具有阶段性意义的任务？是否有重要的功能上线或关键素材产出？
 33→
 34→- 潜在风险与阻碍 (Risks & Bottlenecks)：
 35→  - 延期预警： 识别任务是否出现非预期的停滞（如：进度连续多日无实质变化）。
 36→  - 协作阻塞： 重点区分"计划内排期等待"与"非预期卡点"。识别是否有员工因为前置环节未交付而导致的被迫停工。
 37→  - 情绪状态： 仅在出现高频或明显的负面词汇（如"沟通极度困难"、"无法推进"）时进行提示。严禁对"……"或单纯的语气词进行过度脑补。
 38→
 39→- 异动监控 (Anomaly Detection)：
 40→  - 记录内容过于笼统（如"处理杂事"）或与目标计划严重不符的情况。
 41→
 42→- 管理建议 (Managerial Advice)：
 43→  - 针对上述问题，建议我今天找谁谈话，或者需要开会解决哪个具体痛点？
 44→
 45→# Output Style
 46→- 精简： 过滤掉琐碎的"日常打杂"，只汇报对全局有影响的信息。不要有任何客套和称呼，直接汇报信息
 47→- 直观： 使用 Markdown 表格或清晰的分级标题。
 48→- 犀利： 能够读懂"字里行间"的意思。
 49→- 严谨： 基于事实推断。对于不确定的风险点，使用"疑似"、"需确认"等表述。
 50→
 51→# Constraints
 52→- 禁止简单罗列原文: 必须经过二次加工和逻辑归纳。
 53→- 清晰易读的邮件格式输出: 全程不使用任何复杂 HTML 标签，只使用纯文本、Markdown 基础格式（如标题用##、列表用-或数字列表、分隔线用---），段落之间用空行分隔，排版尽量简洁清爽
 54→- 禁止使用高级职衔：统一使用基础职能称谓。
 55→- 禁止脑补：不推测员工未表达出的心理活动，仅分析字面呈现的进度与阻碍。
 56→- 优先级：优先标注跨职能协作中的"信息不对称"或因反馈滞后导致的非预期停顿。';
 57→    public $queue = 'default';
 58→
 59→    public function handle(): bool
 60→    {
 61→        // 判断今天是否为工作日，是则发送上一个工作日的日报
 62→        $today = now()->toDateString();
 63→        $todayCalendar = ShiftCalendar::where('full_date', $today)->first();
 64→        if (!$todayCalendar || $todayCalendar->is_weekend || $todayCalendar->is_holiday) {
 65→            info('[lbl][0422-AI日报邮件][AiEmailJob] 今天非工作日，跳过', ['date' => $today]);
 66→            return true;
 67→        }
 68→
 69→        // 查上一个工作日
 70→        $lastWorkday = ShiftCalendar::where('is_weekend', 0)
 71→            ->where('is_holiday', 0)
 72→            ->where('full_date', '<', $today)
 73→            ->orderByDesc('full_date')
 74→            ->value('full_date');
 75→
 76→        if (!$lastWorkday) {
 77→            info('[lbl][0422-AI日报邮件][AiEmailJob] 找不到上个工作日，跳过');
 78→            return true;
 79→        }
 80→
 81→        // 白名单用户（sfuser_id + email）
 82→        $whitelistUsers = $this->getWhitelistUsers();
 83→        if (empty($whitelistUsers)) {
 84→            info('[lbl][0422-AI日报邮件][AiEmailJob] 白名单为空，跳过');
 85→            return true;
 86→        }
 87→
 88→        // 额外收件人的邮箱和 token（用于解密）
 89→        $extraConfig = $this->getExtraRecipientConfig();
 90→        if (empty($extraConfig['token'])) {
 91→            info('[lbl][0422-AI日报邮件][AiEmailJob] 额外收件人无有效 token，跳过');
 92→            return true;
 93→        }
 94→
 95→        info('[lbl][0422-AI日报邮件][AiEmailJob] 开始处理', [
 96→            'today' => $today,
 97→            'report_date' => $lastWorkday,
 98→            'whitelist_count' => count($whitelistUsers),
 99→            'whitelist_ids' => array_column($whitelistUsers, 'sfuser_id'),
100→            'extra_emails' => $extraConfig['emails'],
101→        ]);
102→
103→        $processedCount = 0;
104→        $totalUsers = count($whitelistUsers);
105→
106→        foreach ($whitelistUsers as $index => $user) {
107→            $sent = false;
108→            try {
109→                $sent = $this->processUser($user, $lastWorkday, $extraConfig);
110→                if ($sent) {
111→                    ++$processedCount;
112→                }
113→            } catch (\Throwable $e) {
114→                info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$user['sfuser_id']} 处理失败: {$e->getMessage()}", [
115→                    'trace' => mb_substr($e->getTraceAsString(), 0, 500),
116→                ]);
117→            }
118→
119→            // 实际发送了邮件且不是最后一个才 sleep，避免打满 Vertex AI TPM 配额
120→            if ($sent && $index < $totalUsers - 1) {
121→                info('[lbl][0422-AI日报邮件][AiEmailJob] 等待 65s 处理下一个用户');
122→                sleep(65);
123→            }
124→        }
125→
126→        info('[lbl][0422-AI日报邮件][AiEmailJob] 全部完成', [
127→            'processed' => $processedCount,
128→            'total' => $totalUsers,
129→        ]);
130→
131→        return true;
132→    }
