134→    /**
135→     * 获取白名单用户列表（sfuser_id + email），从 OaSetting.special_config 读取.
136→     *
137→     * @return array<int, array{sfuser_id: int, email: string}>
138→     */
139→    private function getWhitelistUsers(): array
140→    {
141→        $setting = OaSetting::where('type', 'daily_report_ai')->select('special_config', 'is_on')->first();
142→        if (!$setting || !$setting->is_on) {
143→            return [];
144→        }
145→
146→        $specialConfig = $setting->special_config ?? [];
147→
148→        // 过滤掉 EXTRA_RECIPIENT（boss 只作为抄送，不单独跑分析）
149→        $extraRecipientIds = AppEnv::isProduction() ? self::EXTRA_RECIPIENT_IDS_PROD : self::EXTRA_RECIPIENT_IDS_STAGING;
150→
151→        return array_values(array_filter($specialConfig, fn ($item) => !empty($item['sfuser_id'])
152→            && !empty($item['email'])
153→            && !in_array($item['sfuser_id'], $extraRecipientIds, true)));
154→    }
155→
156→    /**
157→     * 获取固定额外收件人的邮箱 + token（用第一个有效 token 作为解密凭据）.
158→     *
159→     * @return array{emails: string[], token: string}
160→     */
161→    private function getExtraRecipientConfig(): array
162→    {
163→        $emails = [];
164→        $token = '';
165→        $recipientIds = AppEnv::isProduction() ? self::EXTRA_RECIPIENT_IDS_PROD : self::EXTRA_RECIPIENT_IDS_STAGING;
166→        foreach ($recipientIds as $extraId) {
167→            $mc = MailConfig::where('type', "daily_report_{$extraId}")->first();
168→            if (!$mc) {
169→                continue;
170→            }
171→            $toEmails = Arr::get($mc->config, 'to_email', []);
172→            if (!empty($toEmails)) {
173→                $emails = array_merge($emails, $toEmails);
174→            }
175→            // 取第一个有效 token 作为解密凭据
176→            if (empty($token)) {
177→                $token = Arr::get($mc->config, 'sfuser_authorized_token', '');
178→            }
179→        }
180→
181→        return ['emails' => array_values(array_unique($emails)), 'token' => $token];
182→    }
183→
184→    /**
185→     * 处理单个白名单用户：查该用户能看到的所有日报 → 组装邮件 → 用 EXTRA_RECIPIENT token 解密，发送给额外收件人 + 该用户.
186→     *
187→     * @param array{sfuser_id: int, email: string, nickname?: string} $user
188→     * @param array{emails: string[], token: string} $extraConfig
189→     * @return bool 是否实际发送了邮件
190→     */
191→    private function processUser(array $user, string $reportDate, array $extraConfig): bool
192→    {
193→        $sfuserId = $user['sfuser_id'];
194→        $userEmail = $user['email'];
195→        $userNickname = $user['nickname'] ?? '';
196→        $sfuserToken = $extraConfig['token'];
197→
198→        // 收件人 = 额外收件人邮箱 + 当前白名单用户邮箱
199→        $toEmails = array_values(array_unique(array_merge($extraConfig['emails'], [$userEmail])));
200→
201→        // 获取该用户能看到的所有人（直属下属、部门下属、抄送、关注等）
202→        $dailyService = app(DailyReportService::class);
203→        $subordinates = $dailyService->getSubordinates($sfuserId);
204→        $focusUserIds = array_unique(array_merge(
205→            $subordinates['direct_subordinates'] ?? [],
206→            $subordinates['depart_subordinates'] ?? [],
207→            $subordinates['other_subordinates'] ?? [],
208→            $subordinates['focus_users'] ?? []
209→        ));
210→
211→        if (empty($focusUserIds)) {
212→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 无可查看用户，跳过");
213→            return false;
214→        }
215→
216→        // 拉取日报数据
217→        $data = $dailyService->getOthersDailyReportListEnable(
218→            $reportDate,
219→            $reportDate,
220→            $sfuserId,
221→            array_values($focusUserIds),
222→            10000
223→        );
224→
225→        if (empty($data['reports']['report_list'])) {
226→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 日期={$reportDate} 无日报数据，跳过");
227→            return false;
228→        }
229→
230→        $reportList = $data['reports']['report_list'];
231→
232→        // 组装邮件内容
233→        $content = '';
234→        $no = 0;
235→        foreach ($reportList as $report) {
236→            $nickname = $report['data']['nickname'] ?? '';
237→            if (empty($nickname)) {
238→                continue;
239→            }
240→            $nickname = EncryptService::app()->markEncrString(e($nickname));
241→            $reportContent = EncryptService::app()->markEncrString($report['content']);
242→            ++$no;
243→            $content .= '<p><b>'.$no.'、 '.$nickname.'</b></p>';
244→            $content .= '<div style="border:1px solid #eee;padding:8px;margin-bottom:12px;">'.$reportContent.'</div>';
245→        }
246→
247→        if ($no === 0) {
248→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 无有效日报内容，跳过");
249→            return false;
250→        }
251→
252→        $subjectText = $userNickname !== '' ? "【{$reportDate}】智能日报（{$userNickname}）" : "【{$reportDate}】智能日报";
253→        $subject = EncryptService::app()->markEncrString($subjectText);
254→
255→        $params = [
256→            'decrypt_config' => [
257→                'obj' => '$this',
258→                'decrypt_columns' => [],
259→                'partly_decrypt_columns' => ['content', 'subject'],
260→            ],
261→            'receivers' => [[
262→                'type' => 'token',
263→                'tokens' => [$sfuserToken],
264→                'filter' => 'emails',
265→                'filter_map' => ['emails' => $toEmails],
266→            ]],
267→            'content' => $content,
268→            'subject' => $subject,
269→            'ai_analysis_config' => [
270→                'system_prompt' => self::SYSTEM_PROMPT,
271→                'compress' => true,
272→            ],
273→        ];
274→
275→        info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 发送邮件", [
276→            'report_count' => $no,
277→            'visible_user_count' => count($focusUserIds),
278→            'date' => $reportDate,
279→            'to_emails' => $toEmails,
280→        ]);
281→
282→        $t0 = microtime(true);
283→        $result = CoreApiLib::sendRequest('master-api/mail/send-decr', $params);
284→
285→        info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 发送完成", [
286→            'elapsed' => round(microtime(true) - $t0, 2),
287→            'result_code' => $result['error_code'] ?? null,
288→            'result_msg' => $result['error_msg'] ?? null,
289→        ]);
290→
291→        return true;
292→    }
293→}
